import AppKit
import CloseMyLidCore
import SwiftUI

extension AgentHarness {
    var badgeColor: Color {
        switch self {
        case .claudeCode:
            Color(red: 0.11, green: 0.11, blue: 0.12)
        case .codex:
            Color(red: 0.78, green: 0.78, blue: 0.80)
        case .openCode:
            Color(red: 0.09, green: 0.09, blue: 0.11)
        case .gemini:
            Color(red: 0.96, green: 0.96, blue: 0.98)
        case .copilot:
            Color(red: 0.05, green: 0.07, blue: 0.09)
        case .cursor:
            Color(red: 0.05, green: 0.05, blue: 0.06)
        case .pi:
            Color(red: 0.10, green: 0.10, blue: 0.12)
        }
    }

    @MainActor var icon: NSImage? {
        Self.iconCache[self]
    }

    @MainActor private static let iconCache: [AgentHarness: NSImage] = {
        var images: [AgentHarness: NSImage] = [:]
        for harness in AgentHarness.allCases {
            if let image = NSImage(data: Data(harness.iconSVG.utf8)) {
                images[harness] = image
            }
        }
        return images
    }()

